def regex_match(text, pattern, ti=0, pi=0):
    if pi == len(pattern):
        return ti == len(text)
    first_match = ti < len(text) and (
        pattern[pi] == '.' or pattern[pi] == text[ti]
    )
    if pi + 1 < len(pattern) and pattern[pi + 1] == '*':
        # Try skip (0 matches) or consume (1+ matches)
        return (regex_match(text, pattern, ti, pi + 2) or
                (first_match and regex_match(text, pattern, ti + 1, pi)))
    return first_match and regex_match(text, pattern, ti + 1, pi + 1)
